xf:group.script:
/**
* //property handling
* $w.log("id:" + options.id);
* $w.log("date:" + options.date);
* $w.log("ref:" + options.ref);
*
* //event trigger
* udc_obj.trigger("onBtnCalendarClick"); 
*/

// 초기 수행함수 
this.initMonthCalendar = function() {
	this.today = "";
	this.selectedDate = "";

	var tmpDate = new Date();
	var year = tmpDate.getFullYear();
	var month = tmpDate.getMonth() + 1;

	if (parseInt(month) < 10) {
		month = "0" + month;
	}
	this.today = year + month + "";

	tbx_Year.setValue(year);

	// ref 설젇 
	if (options.ref != "") {
		ibx_Date.setRef(options.ref);
	}
	if (ibx_Date.getValue() == "" && options.date != undefined) {
		// udc의 초기 설정값
		ibx_Date.setValue(options.date);
	}
};

this.showMonthCalendar = function() {
	this.selectedDate = ibx_Date.getValue();

	if (this.selectedDate.length >= 4) {
		this.changeYear(this.selectedDate);
	}
	if (div_Month.getStyle("display") == "none") {
		div_Month.setStyle("display", "");
	} else {
		div_Month.setStyle("display", "none");
	}
};

// 시작 년도가 변경된 경우
this.changeYear = function(strDate) {
	tbx_Year.setValue(strDate.substr(0, 4));
	for (var i = 1; i <= 12; i++) {
		// 월 구성 '##'
		var month = "00" + i;
		month = month.substr(month.length - 2, 2);

		eval("btn_Month" + month).removeClass("today");

		// 변경된 년도가 올해인 경우 현재 월에 today 클래스를 추가하여 화면에 표시되도록 함 
		if (strDate.substr(0, 4) == this.today.substr(0, 4)) {
			if (month == this.today.substr(4, 2)) {
				eval("btn_Month" + month).addClass("today");
			}
		}
		// 선택된 월 표시
		eval("btn_Month" + month).removeClass("selected");
		if (strDate.substr(0, 4) == this.selectedDate.substr(0, 4)) {
			if (month == this.selectedDate.substr(4, 2)) {
				eval("btn_Month" + month).addClass("selected");
			}
		}
	}
};

// 시작월 클릭시
this.clickMonths = function(strMonth) {
	for(var i = 1; i <= 12; i++) {
		// 월 구성 '##'
		var month = "00" + i;
		month = month.substr(month.length - 2, 2);
		eval("btn_Month" + month).removeClass("selected");

		if (month == strMonth) {
			eval("btn_Month" + month).addClass("selected");
		}
	}

	// this.selectedDate = tbx_Year.getValue() + "-" + strMonth;
	this.selectedDate = tbx_Year.getValue() + strMonth;
	ibx_Date.setValue(this.selectedDate);
	var tmpValue = {originalValue : ibx_Date.originalValue, value : ibx_Date.getValue()};

	div_Month.setStyle("display", "none");
	udc_obj.trigger("onchangeValue" , tmpValue);
	// udc_obj.changeMonth();
};

// 확인 버튼 클릭시 
this.changeMonth = function() {
	// if (this.selectedDate.length == 7) {
		// ibx_Date.setValue(this.selectedDate);
	// }
	if (this.selectedDate.length == 6) {
		ibx_Date.setValue(this.selectedDate);
	}

	div_Month.setStyle("display", "none");
};

/**
 * 년월 문자열 display
 * @param <String> value yyyyMM
 * @return yyyy-MM
 */
udc_obj.displayCalMonth = function(value) {
	var date_dlmt = "-";
	value = value.replaceAll("-", "");
	var year_data = "";
	var month_data = "";
	var i;
	var flagYn;
	if (value.length == 6) {
		for (i = 0; i < 6; i++) {
			var c = value.charAt(i);
			if ((c < '0' || c > '9')) {
				flagYn = false;
			} else {
				flagYn = true;
			}
			if (i < 4) {
				year_data += c;
			} else if (i >= 4 && i < 6) {
				month_data += c;
			}
		}
		if (flagYn) {
			var mnthst = month_data;
			var mnth = parseInt(mnthst, 10);
			if (mnth < 1 || mnth > 12) {
				ibx_Date.setValue( "" );
				// return "";
			} else {
				ibx_Date.setValue(value.substr(0, 4) + date_dlmt + scwin.lpad(value.substr(4, 2), 2, "0"));
				// return value.substr(0, 4) + date_dlmt + scwin.lpad(value.substr(4, 2), 2, "0");
			}
		} else {
			ibx_Date.setValue("");
			// return "";
		}
	}
	if (value.length < 6) {
		ibx_Date.setValue("");
		// return "";
	}
};

/**
 * 입력받은 str 의 왼쪽을 num만큼 chr로 채운다.
 * 
 * @date 2014. 12. 10.
 * @param <String> str 원본 문자열
 * @param <Number> num 채울 자리수
 * @param <String> chr 채울 문자
 * @example utilLib.lpad("1", 3, "0")
 * @return
 */
scwin.lpad = function(str, num, chr) {
	if (!str || !chr || str.length >= num) {
		return str;
	}

	var max = num - str.length;
	for ( var i = 0; i < max; i++) {
		str = chr + str;
	}

	return str;
};

/**
 * 년월 문자열 validate
 * @param <String> value yyyyMM
 * @return
 */
scwin.validateCalMonth = function(value) {
	if (value.length < 5) {
		comLib.alert($p, "날짜 데이터 자리수가 맞지 않습니다.", "scwin.validateCalMonthCallback");
	}

	if (parseInt(value.substr(4, 2)) > 12) {
		comLib.alert($p, "날짜 월 데이터가 맞지 않습니다.", "scwin.validateCalMonthCallback");
	}

	return value;
};

scwin.validateCalMonthCallback = function() {
	ibx_Date.focus();
};

udc_obj.getDate = function() {
	if(ibx_Date.getValue() == "") {
		return null;
	} else {
		return ibx_Date.getValue();
	}
};

udc_obj.setDate = function(strDate) {
	ibx_Date.setValue(strDate);
};

//초기 실행함수 수행
this.initMonthCalendar();
